-- --------------------------------------------------------
-- CDN-Fuel Master Database Schema
-- Optimized for QBCore/Qbox
-- --------------------------------------------------------

--
-- Table structure for `fuel_stations`
--

CREATE TABLE IF NOT EXISTS `fuel_stations` (
  `location` int(11) NOT NULL,
  `owned` int(11) DEFAULT NULL,
  `owner` varchar(50) DEFAULT NULL,
  `fuel` int(11) DEFAULT NULL, -- Estoque de Gasolina
  `diesel` int(11) DEFAULT 0, -- Estoque de Diesel
  `ethanol` int(11) DEFAULT 0, -- Estoque de Etanol
  `fuelprice` int(11) DEFAULT NULL, -- Preço Gasolina
  `dieselprice` int(11) DEFAULT NULL, -- Preço Diesel
  `ethanolprice` int(11) DEFAULT NULL, -- Preço Etanol
  `balance` int(255) DEFAULT NULL,
  `label` varchar(255) DEFAULT NULL,
  `shutoff` tinyint(1) DEFAULT 0,
  `zones` longtext DEFAULT NULL,
  `minz` float DEFAULT NULL,
  `maxz` float DEFAULT NULL,
  `pedmodel` varchar(50) DEFAULT NULL,
  `pedcoords` text DEFAULT NULL,
  `cost` int(11) DEFAULT 100000,
  `pumpheightadd` float DEFAULT 2.1,
  `electricchargercoords` text DEFAULT NULL,
  `fuelpumpcoords` longtext DEFAULT NULL,
  `logo` longtext DEFAULT NULL,
  `type` varchar(50) DEFAULT 'car',
  `unloadcoords` text DEFAULT NULL,
  `stock_level` int(11) DEFAULT 0, -- Nível de upgrade de capacidade de estoque
  `loyalty_level` int(11) DEFAULT 0, -- Nível de plano de fidelidade (Combustível)
  -- Sistema de Gestão Elétrica
  `electric_consumed` float DEFAULT 0, -- kWh consumidos desde a última fatura
  `electric_bill_due` datetime DEFAULT NULL, -- Data de vencimento da próxima fatura
  `electric_debt` int(11) DEFAULT 0, -- Valor total em dívida elétrica
  `electric_loyalty_level` int(11) DEFAULT 0, -- Nível de plano de fidelidade (Elétrico)
  `electric_status` tinyint(1) DEFAULT 1, -- 1: Ativo, 0: Desativado por falta de pagamento
  `electric_debt_since` timestamp NULL DEFAULT NULL, -- Data em que a dívida elétrica começou (para carência)
  `is_purchasable` tinyint(1) DEFAULT 1, -- 1: Comprável, 0: Não comprável
  PRIMARY KEY (`location`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

--
-- Table structure for `fuel_vehicle_mappings`
--

CREATE TABLE IF NOT EXISTS `fuel_vehicle_mappings` (
  `name` varchar(50) NOT NULL,
  `fuel_type` varchar(20) NOT NULL DEFAULT 'gasoline',
  `is_model` tinyint(1) DEFAULT 0,
  PRIMARY KEY (`name`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

--
-- Table structure for `fuel_station_sales`
--

CREATE TABLE IF NOT EXISTS `fuel_station_sales` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `station_location` int(11) NOT NULL,
  `buyer_name` varchar(50) DEFAULT NULL,
  `amount` float DEFAULT NULL,
  `cost` int(11) DEFAULT NULL,
  `payment_type` varchar(20) DEFAULT NULL,
  `date` timestamp NOT NULL DEFAULT current_timestamp(),
  
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

--
-- Table structure for `fuel_station_weekly_logs`
--

CREATE TABLE IF NOT EXISTS `fuel_station_weekly_logs` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `station_location` int(11) DEFAULT NULL,
  `start_date` datetime DEFAULT NULL,
  `end_date` datetime DEFAULT NULL,
  `total_liters` int(11) DEFAULT 0,
  `peak_liters` int(11) DEFAULT 0,
  `total_revenue` int(11) DEFAULT 0,
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

